class FormatError(Exception):
	"""
	Raised when an input file (FASTA or FASTQ) is malformatted.
	"""


def _shorten(s, n=20):
	"""Shorten string s to at most n characters, appending "..." if necessary."""
	if s is None:
		return None
	if len(s) > n:
		s = s[:n-3] + '...'
	return s


cdef class Sequence(object):
	"""
	A record in a FASTQ file. Also used for FASTA (then the qualities attribute
	is None). qualities is a string and it contains the qualities encoded as
	ascii(qual+33).

	If an adapter has been matched to the sequence, the 'match' attribute is
	set to the corresponding AdapterMatch instance.
	"""
	cdef:
		public str name
		public str sequence
		public str qualities
		public object match
		public bint twoheaders

	def __init__(self, str name, str sequence, str qualities=None,
			  bint twoheaders=False, match=None):
		"""Set qualities to None if there are no quality values"""
		self.name = name
		self.sequence = sequence
		self.qualities = qualities
		self.twoheaders = twoheaders
		self.match = match
		if qualities is not None and len(qualities) != len(sequence):
			rname = _shorten(name)
			raise FormatError("In read named {0!r}: length of quality sequence ({1}) and length of read ({2}) do not match".format(
				rname, len(qualities), len(sequence)))

	def __getitem__(self, key):
		"""slicing"""
		return self.__class__(
			self.name,
			self.sequence[key],
			self.qualities[key] if self.qualities is not None else None,
			self.twoheaders,
			self.match)

	def __repr__(self):
		qstr = ''
		if self.qualities is not None:
			qstr = ', qualities={0!r}'.format(_shorten(self.qualities))
		return '<Sequence(name={0!r}, sequence={1!r}{2})>'.format(_shorten(self.name), _shorten(self.sequence), qstr)

	def __len__(self):
		return len(self.sequence)

	def __richcmp__(self, other, int op):
		if 2 <= op <= 3:
			eq = self.name == other.name and \
				self.sequence == other.sequence and \
				self.qualities == other.qualities
			if op == 2:
				return eq
			else:
				return not eq
		else:
			raise NotImplementedError()

	def __reduce__(self):
		return (Sequence, (self.name, self.sequence, self.qualities, self.twoheaders))

	def write(self, outfile):
		if self.qualities is not None:
			s = '@' + self.name + '\n' + self.sequence + '\n+'
			if self.twoheaders:
				s += self.name
			s += '\n' + self.qualities + '\n'
		else:
			s = '>' + self.name + '\n' + self.sequence + '\n'
		outfile.write(s)


class FastqReader(object):
	"""
	Reader for FASTQ files. Does not support multi-line FASTQ files.
	"""
	def __init__(self, file, sequence_class=Sequence):
		"""
		file is a filename or a file-like object.
		If file is a filename, then .gz files are supported.

		colorspace -- Usually (when this is False), there must be n characters in the sequence and
		n quality values. When this is True, there must be n+1 characters in the sequence and n quality values.
		"""
		if isinstance(file, basestring):
			file = xopen(file, 'r')
		self.fp = file
		self.sequence_class = sequence_class
		self.delivers_qualities = True

	def __iter__(self):
		"""
		Return tuples: (name, sequence, qualities).
		qualities is a string and it contains the unmodified, encoded qualities.
		"""
		cdef int i = 0
		cdef int strip
		cdef str line, name, qualities, sequence
		cdef bint twoheaders
		sequence_class = self.sequence_class

		it = iter(self.fp)
		line = next(it)
		if not (line and line[0] == '@'):
			raise FormatError("at line {0}, expected a line starting with '@'".format(i+1))
		strip = -2 if line.endswith('\r\n') else -1
		name = line[1:strip]

		i = 1
		for line in it:
			if i == 0:
				if not (line and line[0] == '@'):
					raise FormatError("at line {0}, expected a line starting with '@'".format(i+1))
				name = line[1:strip]
			elif i == 1:
				sequence = line[:strip]
			elif i == 2:
				if line == '+\n':  # check most common case first
					twoheaders = False
				else:
					line = line[:strip]
					if not (line and line[0] == '+'):
						raise FormatError("at line {0}, expected a line starting with '+'".format(i+1))
					if len(line) > 1:
						twoheaders = True
						if not line[1:] == name:
							raise FormatError(
								"At line {0}: Sequence descriptions in the FASTQ file don't match "
								"({1!r} != {2!r}).\n"
								"The second sequence description must be either empty "
								"or equal to the first description.".format(i+1,
									name, line[1:]))
					else:
						twoheaders = False
			elif i == 3:
				if len(line) == len(sequence) - strip:
					qualities = line[:strip]
				else:
					qualities = line.rstrip('\r\n')
				yield sequence_class(name, sequence, qualities, twoheaders=twoheaders)
			i = (i + 1) % 4
		if i != 0:
			raise FormatError("FASTQ file ended prematurely")

	def __enter__(self):
		if self.fp is None:
			raise ValueError("I/O operation on closed FastqReader")
		return self

	def __exit__(self, *args):
		self.fp.close()

cdef class Parser:

    cdef list tokens
    cdef int i # token index
    cdef int n # number of tokens
    cdef int j # sanity counter
    cdef int m # number of characters
    cdef bytes toParse

    cdef readDict(Parser self):
        out = dict()
        cdef Token token
        while True:
            self.j += 1
            if self.j > self.m: 
                raise Exception("WXNABBCFCA\n%s" % self.toParse)
            if self.i >= self.n: raise Exception("no }?")
            token = <Token> self.tokens[self.i]
            if token.type_ == CLOSE_CURLY:
                self.i += 1
                return out
            elif token.type_ == CLOSE_PAREN or token.type_ == CLOSE_BRACKET:
                raise Exception("mismatched [")
            elif token.type_ == COMMA:
                self.i += 1
            else:
                key = self.readValue()
                token = <Token> self.tokens[self.i]
                if token.type_ != COLON: raise Exception("bad dict?")
                self.i += 1
                value = self.readValue()
                out[key] = value

    cdef readList(Parser self):
        out = list()
        cdef Token token
        while True:
            self.j += 1
            if self.j > self.m: 
                raise Exception("MRDKZDUXVS\n%s" % self.toParse)
            if self.i >= self.n: raise Exception("no ]?")
            token = <Token> self.tokens[self.i]
            if token.type_ == CLOSE_BRACKET:
                self.i += 1
                return out
            elif token.type_ == COMMA:
                self.i += 1
            elif token.type_ == CLOSE_PAREN or token.type_ == CLOSE_CURLY:
                raise Exception("mismatched [")
            else:
                out.append( self.readValue() )

    cdef readPyob(Parser self,str name):
        out = Pyob(name)
        cdef Token token
        cdef Token t2
        cdef Token t3
        while True:
            self.j += 1
            if self.j > self.m: 
                raise Exception("OHWYBQMBOY\n%s" % self.toParse)
            if self.i >= self.n: raise Exception("no )?")
            token = <Token> self.tokens[self.i]
            if token.type_ == CLOSE_PAREN:
                self.i += 1
                return out
            elif token.type_ == CLOSE_CURLY or token.type_ == CLOSE_BRACKET:
                raise Exception("mismatched (")
            elif token.type_ == COMMA:
                self.i += 1
            else:
                if token.type_ == BAREWORD and self.i + 2 < self.n:
                    t2 = <Token> self.tokens[self.i+1]
                    if t2.type_ == EQ_SIGN:
                        self.i += 2
                        value = self.readValue()
                        out.keyed[token.value_] = value
                    else:
                        out.ordered.append( self.readValue() )
                else:
                    out.ordered.append( self.readValue() )

    cdef readValue(Parser self):
        if self.i >= self.n: raise Exception("out of tokens?")
        cdef Token token = <Token> self.tokens[self.i]
        cdef Token t2
        self.i += 1
        if token.type_ == QUOTED: return token.value_
        if token.type_ == NUMBER: return token.value_
        if token.type_ == BAREWORD:
            if self.i < self.n:
                t2 = <Token> self.tokens[self.i]
                if t2.type_ == OPEN_PAREN:
                    self.i += 1
                    return self.readPyob(token.value_)
            if token.value_.lower() == "true": return True
            if token.value_.lower() == "false": return False
            if token.value_.lower() == "none": return None
            if token.value_.lower() == "null": return None
            if token.value_.lower() == "nan": return float('nan')
            if token.value_.lower() == "inf": return float('inf')
            raise Exception("bad bareword:" + token.value_)
        if token.type_ == OPEN_BRACKET: return self.readList()
        if token.type_ == OPEN_CURLY: return self.readDict()
        raise Exception("don't know how to parse: %r" % token)

    def parse(Parser self, toParse):
        self.toParse = toParse
        self.tokens = tokenize(toParse)
        self.j = 0
        self.i = 0
        self.n = len(self.tokens)
        self.m = len(self.toParse)
        return self.readValue()

def parse(thing):
    parser = Parser()
    return parser.parse(thing)
